// replicationTracker records the primary WAL position of successful writes.
//
// Reads normally go to the replica, but after this process has accepted a write
// for an account we must not serve that account from the replica until the
// replica has replayed at least the WAL record containing the write. A fixed
// time-based pin is not sufficient: replication can lag for longer than the pin
// window, and falling back to a lagging replica would return a pre-write value.
type replicationTracker struct {
	mu  sync.Mutex
	lsn map[string]string
}

func newReplicationTracker() *replicationTracker {
	return &replicationTracker{lsn: make(map[string]string)}
}

func (t *replicationTracker) mark(account, lsn string) {
	t.mu.Lock()
	defer t.mu.Unlock()

	cur, ok := t.lsn[account]
	if !ok || cur == "" || lsn == "" || compareLSN(lsn, cur) > 0 {
		t.lsn[account] = lsn
	}
}

func (t *replicationTracker) required(account string) (string, bool) {
	t.mu.Lock()
	defer t.mu.Unlock()
	lsn, ok := t.lsn[account]
	return lsn, ok
}

func (t *replicationTracker) clearIfSatisfied(account, replayedThrough string) {
	t.mu.Lock()
	defer t.mu.Unlock()

	cur, ok := t.lsn[account]
	if ok && cur != "" && compareLSN(replayedThrough, cur) >= 0 {
		delete(t.lsn, account)
	}
}

// compareLSN compares PostgreSQL LSN strings (for example "0/16B6C50"). It
// returns -1, 0, or 1 when a < b, a == b, or a > b. Invalid values compare as
// equal; PostgreSQL supplies these strings, so invalid input is not expected.
func compareLSN(a, b string) int {
